import{_ as e,o as i,c as d,e as t}from"./app-25fa875f.js";const a={},n=t(`<h1 id="syzkaller-description-syntax" tabindex="-1"><a class="header-anchor" href="#syzkaller-description-syntax" aria-hidden="true">#</a> Syzkaller - Description Syntax</h1><p>Created by : Mr Dk.</p><p>2019 / 07 / 04 14:49</p><p>Nanjing, Jiangsu, China</p><hr><h2 id="syscall-descriptions" tabindex="-1"><a class="header-anchor" href="#syscall-descriptions" aria-hidden="true">#</a> Syscall Descriptions</h2><p><code>syz-fuzzer</code> 进程产生测试 kernel 系统调用的程序，由 <code>syz-executor</code> 进行执行。对应的系统调用接口需要在指定目录下被声明，从而使 syzkaller 能够利用这些系统调用接口生成程序。</p><p>系统调用描述文件位于 syzkaller 目录的 <code>/sys/:OS/:*.txt</code> 中：比如，<code>sys/linux/dev_snd_midi.txt</code> 中包含了 Linux MIDI 接口的描述。</p><hr><h2 id="syscall-descriptions-syntax" tabindex="-1"><a class="header-anchor" href="#syscall-descriptions-syntax" aria-hidden="true">#</a> Syscall Descriptions Syntax</h2><h3 id="overview" tabindex="-1"><a class="header-anchor" href="#overview" aria-hidden="true">#</a> Overview</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>open(file filename, flags flags[open_flags], mode flags[open_mode]) fd
read(fd fd, buf buffer[out], count len[buf]) len[buf]
close(fd fd)
open_mode = S_IRUSR, S_IWUSR, S_IXUSR, S_IRGRP, S_IWGRP, S_IXGRP, S_IROTH, S_IWOTH, S_IXOTH
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="entry" tabindex="-1"><a class="header-anchor" href="#entry" aria-hidden="true">#</a> Entry</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>syscallname &quot;(&quot; [arg [&quot;,&quot; arg]*] &quot;)&quot; [type]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>即，系统调用名，之后带括号，括号内是参数，最后是系统调用的返回值类型，如：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>open(...) fd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>系统调用名为 <code>open</code>，返回值类型为 <code>fd</code></li></ul><h3 id="arguments" tabindex="-1"><a class="header-anchor" href="#arguments" aria-hidden="true">#</a> Arguments</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>arg = argname type
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>每个参数可以分为两部分：</p><ul><li>参数名</li><li>参数类型</li></ul><p>如：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>open(file filename, ...) fd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>第一个参数名为 <code>file</code></li><li>参数类型为 <code>filename</code></li></ul><h3 id="argument-name" tabindex="-1"><a class="header-anchor" href="#argument-name" aria-hidden="true">#</a> Argument Name</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>argname = identifier
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="type" tabindex="-1"><a class="header-anchor" href="#type" aria-hidden="true">#</a> Type</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>type = typename [ &quot;[&quot; type-options &quot;]&quot; ]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>类型包含两部分：</p><ul><li><code>typename</code> - 类型名 <ul><li><code>const</code></li><li><code>intN</code></li><li><code>intptr</code></li><li><code>flags</code></li><li><code>array</code></li><li><code>ptr</code></li><li><code>string</code></li><li><code>strconst</code></li><li><code>filename</code></li><li><code>len</code></li><li><code>bytesize</code></li><li><code>bytesizeN</code></li><li><code>bitsize</code></li><li><code>vma</code></li><li><code>proc</code></li></ul></li><li><code>type-options</code> - 类型选项，在类型名后加 <code>[]</code> (可选)</li></ul><h3 id="ints" tabindex="-1"><a class="header-anchor" href="#ints" aria-hidden="true">#</a> Ints</h3><ul><li><code>int8</code></li><li><code>int16</code></li><li><code>int32</code></li><li><code>int64</code></li><li><code>intptr</code> - 代表一个指针尺寸的整数，比如 C 中的 <code>long</code></li></ul><p>加入 <code>be</code> 后缀表示大端 - <code>int16be</code></p><p>可以对整数指定范围：<code>int32[0:100]</code>，也可以指定位长度：<code>int64:N</code>：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>example_struct {
    f0  int8                  # random 1-byte integer
    f1  const[0x42, int16be]  # const 2-byte integer with value 0x4200 (big-endian 0x42)
    f2  int32[0:100]          # random 4-byte integer with values from 0 to 100 inclusive
    f3  int64:20              # random 20-bit bitfield
}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="structs" tabindex="-1"><a class="header-anchor" href="#structs" aria-hidden="true">#</a> Structs</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>&lt;structname&gt; {
    fieldname type
    ...
} [ &lt;attribute&gt; ]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>Attribute</th><th>Description</th></tr></thead><tbody><tr><td><code>&quot;packed&quot;</code></td><td>No paddings, default alignment 1</td></tr><tr><td><code>&quot;align_N&quot;</code></td><td>Alignment N</td></tr><tr><td><code>&quot;size&quot;</code></td><td>Padded up to the specified size</td></tr></tbody></table><h3 id="unions" tabindex="-1"><a class="header-anchor" href="#unions" aria-hidden="true">#</a> Unions</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>&lt;unionname&gt; {
    fieldname type
    ...
} [ &lt;attribute&gt; ]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>Attribute</th><th>Description</th></tr></thead><tbody><tr><td><code>&quot;varlen&quot;</code></td><td>union size is not maximum of all option but rather length of a particular chosen option</td></tr><tr><td><code>&quot;size&quot;</code></td><td>the union is padded up to the specified size</td></tr></tbody></table><h3 id="resources" tabindex="-1"><a class="header-anchor" href="#resources" aria-hidden="true">#</a> Resources</h3><p>代表需要从一个系统调用的输出中传递到另一个系统调用的输入的值：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>resource &lt;identifier&gt; [&lt;underlying_type&gt;] ...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>比如：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>resource fd[int32]: 0xffffffffffffffff, AT_FDCWD, 1000000
resource sock[fd]
resource sock_unix[sock]

socket(...) sock
accept(fd sock, ...) sock
listen(fd sock, backlog int32)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>&quot;resource&quot; 声明</li><li>resource 名称</li><li>resource 的类型 <ul><li><code>int8</code>、<code>int16</code>、<code>int32</code>、<code>int64</code> 、<code>intptr</code> 或另一个 resource (继承)</li></ul></li><li>冒号之后可以加其余选项 <ul><li>resource 可以使用一些特殊值</li></ul></li></ul><h3 id="type-aliases" tabindex="-1"><a class="header-anchor" href="#type-aliases" aria-hidden="true">#</a> Type Aliases</h3><p>可以使用低层类型构造新的类型</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>type identifier underlying_type
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>比如：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>type signalno int32[0:65]
type net_port proc[20000, 4, int16be]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>一些内置的构造类型：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>type bool8	int8[0:1]
type bool16	int16[0:1]
type bool32	int32[0:1]
type bool64	int64[0:1]
type boolptr	intptr[0:1]

type filename string[filename]

type buffer[DIR] ptr[DIR, array[int8]]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="type-templates" tabindex="-1"><a class="header-anchor" href="#type-templates" aria-hidden="true">#</a> Type Templates</h3><h3 id="length" tabindex="-1"><a class="header-anchor" href="#length" aria-hidden="true">#</a> Length</h3><h3 id="proc" tabindex="-1"><a class="header-anchor" href="#proc" aria-hidden="true">#</a> Proc</h3><hr>`,58),l=[n];function s(r,c){return i(),d("div",null,l)}const u=e(a,[["render",s],["__file","Syzkaller Description Syntax.html.vue"]]);export{u as default};
